import { LLMConfig } from "./llm-types.ts";

const DEFAULT_TEMPERATURE = 0.3;
const MAX_ALLOWED_TEMPERATURE = 0.3;
const DEFAULT_TIMEOUT_MS = 30000;
const MAX_RETRIES = 2;

export function loadLLMConfig(): LLMConfig {
  const provider = (Deno.env.get("LLM_PROVIDER") || "openai") as "openai" | "anthropic";

  let model: string;
  if (provider === "openai") {
    model = Deno.env.get("OPENAI_MODEL") || "gpt-4o-mini";
  } else {
    model = Deno.env.get("ANTHROPIC_MODEL") || "claude-3-5-haiku-20241022";
  }

  const temperature = Math.min(
    parseFloat(Deno.env.get("LLM_TEMPERATURE") || String(DEFAULT_TEMPERATURE)),
    MAX_ALLOWED_TEMPERATURE
  );

  const max_tokens = parseInt(
    Deno.env.get("LLM_MAX_TOKENS") || "2000",
    10
  );

  const timeout_ms = parseInt(
    Deno.env.get("LLM_TIMEOUT_MS") || String(DEFAULT_TIMEOUT_MS),
    10
  );

  const max_retries = parseInt(
    Deno.env.get("LLM_MAX_RETRIES") || String(MAX_RETRIES),
    10
  );

  return {
    provider,
    model,
    temperature,
    max_tokens,
    timeout_ms,
    max_retries,
  };
}

export function validateLLMConfig(config: LLMConfig): { valid: boolean; error?: string } {
  if (config.temperature > MAX_ALLOWED_TEMPERATURE) {
    return {
      valid: false,
      error: `Temperature ${config.temperature} exceeds maximum ${MAX_ALLOWED_TEMPERATURE}`,
    };
  }

  if (config.max_tokens < 100 || config.max_tokens > 4000) {
    return {
      valid: false,
      error: `Max tokens ${config.max_tokens} out of range (100-4000)`,
    };
  }

  if (config.max_retries < 0 || config.max_retries > 5) {
    return {
      valid: false,
      error: `Max retries ${config.max_retries} out of range (0-5)`,
    };
  }

  return { valid: true };
}

import { AssembledPrompts } from "./types.ts";
import { LLMCallContext } from "./llm-types.ts";

export interface GuardViolation {
  code: string;
  message: string;
}

export interface GuardResult {
  valid: boolean;
  violations: GuardViolation[];
}

export function validateLLMCallContext(context: LLMCallContext): GuardResult {
  const violations: GuardViolation[] = [];

  if (!context.enforcement_passed) {
    violations.push({
      code: "ENFORCEMENT_NOT_PASSED",
      message: "LLM call refused: enforcement must pass before calling LLM",
    });
  }

  if (!context.prompt_order_valid) {
    violations.push({
      code: "INVALID_PROMPT_ORDER",
      message: "LLM call refused: prompt order validation failed",
    });
  }

  if (context.canon_appended_last === false) {
    violations.push({
      code: "CANON_NOT_LAST",
      message: "LLM call refused: canon context must be appended last",
    });
  }

  return {
    valid: violations.length === 0,
    violations,
  };
}

export function validatePromptOrder(assembled: AssembledPrompts): boolean {
  const expectedOrder = [
    "gemma-core-system-v1",
    "boundary-safety-v1",
    "state-template-v1",
    "knowledge-canon-v1",
  ];

  if (assembled.metadata.prompt_versions.length < expectedOrder.length) {
    return false;
  }

  for (let i = 0; i < expectedOrder.length; i++) {
    if (assembled.metadata.prompt_versions[i] !== expectedOrder[i]) {
      return false;
    }
  }

  return true;
}

export function validateCanonPosition(assembled: AssembledPrompts): boolean {
  if (!assembled.metadata.canon_included) {
    return true;
  }

  if (assembled.prompts.length < 5) {
    return false;
  }

  const canonPrompt = assembled.prompts[assembled.prompts.length - 1];

  if (!canonPrompt.includes("KNOWLEDGE CANON CONTEXT")) {
    return false;
  }

  return true;
}

export function createLLMCallContext(
  assembled: AssembledPrompts,
  request_id: string,
  user_id: string
): LLMCallContext {
  const promptOrderValid = validatePromptOrder(assembled);
  const canonPositionValid = validateCanonPosition(assembled);

  return {
    request_id,
    user_id,
    enforcement_passed: true,
    prompt_order_valid: promptOrderValid,
    canon_appended_last: canonPositionValid,
  };
}

import { LLMConfig, LLMResponse } from "./llm-types.ts";

interface OpenAIMessage {
  role: "system" | "user" | "assistant";
  content: string;
}

interface OpenAIChatRequest {
  model: string;
  messages: OpenAIMessage[];
  temperature: number;
  max_tokens: number;
}

interface OpenAIChatResponse {
  id: string;
  object: string;
  created: number;
  model: string;
  choices: Array<{
    index: number;
    message: {
      role: string;
      content: string;
    };
    finish_reason: string;
  }>;
  usage: {
    prompt_tokens: number;
    completion_tokens: number;
    total_tokens: number;
  };
}

async function callOpenAIWithTimeout(
  url: string,
  body: OpenAIChatRequest,
  apiKey: string,
  timeoutMs: number
): Promise<Response> {
  const controller = new AbortController();
  const timeoutId = setTimeout(() => controller.abort(), timeoutMs);

  try {
    const response = await fetch(url, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "Authorization": `Bearer ${apiKey}`,
      },
      body: JSON.stringify(body),
      signal: controller.signal,
    });

    clearTimeout(timeoutId);
    return response;
  } catch (error) {
    clearTimeout(timeoutId);
    throw error;
  }
}

export async function callOpenAI(
  prompts: string[],
  config: LLMConfig,
  userMessage?: string
): Promise<LLMResponse> {
  const apiKey = Deno.env.get("OPENAI_API_KEY");
  if (!apiKey) {
    return {
      success: false,
      response: "",
      metadata: {
        model: config.model,
        provider: "openai",
        timestamp: new Date().toISOString(),
      },
      error: "OPENAI_API_KEY not configured",
    };
  }

  const messages: OpenAIMessage[] = prompts.map((prompt) => ({
    role: "system",
    content: prompt,
  }));

  if (userMessage) {
    messages.push({
      role: "user",
      content: userMessage,
    });
  }

  const requestBody: OpenAIChatRequest = {
    model: config.model,
    messages,
    temperature: config.temperature,
    max_tokens: config.max_tokens,
  };

  let lastError: Error | null = null;
  let retryCount = 0;

  for (let attempt = 0; attempt <= config.max_retries; attempt++) {
    try {
      const response = await callOpenAIWithTimeout(
        "https://api.openai.com/v1/chat/completions",
        requestBody,
        apiKey,
        config.timeout_ms
      );

      if (!response.ok) {
        const errorText = await response.text();
        throw new Error(`OpenAI API error: ${response.status} - ${errorText}`);
      }

      const data: OpenAIChatResponse = await response.json();

      return {
        success: true,
        response: data.choices[0].message.content,
        metadata: {
          model: data.model,
          provider: "openai",
          prompt_tokens: data.usage.prompt_tokens,
          completion_tokens: data.usage.completion_tokens,
          total_tokens: data.usage.total_tokens,
          timestamp: new Date().toISOString(),
        },
      };
    } catch (error) {
      lastError = error as Error;
      retryCount = attempt;

      if (attempt < config.max_retries) {
        await new Promise((resolve) => setTimeout(resolve, 1000 * (attempt + 1)));
      }
    }
  }

  return {
    success: false,
    response: "",
    metadata: {
      model: config.model,
      provider: "openai",
      timestamp: new Date().toISOString(),
    },
    error: lastError?.message || "Unknown error",
  };
}

